#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,M,X; scanf("%d %d %d", &N, &M, &X);
        int tmp;
        for(int i=0;i<N;i++) scanf("%d", &tmp);
        for(int i=0;i<M;i++) scanf("%d", &tmp);
        int intersectVal=0;
        for(int i=0;i<X;i++){
            scanf("%d", &tmp);
            if(i==0) intersectVal=tmp;
        }
        printf("%d\n", intersectVal);
    }
    return 0;
}

