code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int M = Integer.parseInt(st.nextToken());
            int X = Integer.parseInt(st.nextToken());
            // read and ignore first list
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) st.nextToken();
            // read and ignore second list
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < M; i++) st.nextToken();
            // read common tail, capture first value
            st = new StringTokenizer(br.readLine());
            int intersectVal = Integer.parseInt(st.nextToken());
            // remaining X-1 values can be ignored
            sb.append(intersectVal).append('\n');
        }
        System.out.print(sb.toString());
    }
}

