import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); X = int(next(it))
        for _ in range(N):
            next(it)  # discard
        for _ in range(M):
            next(it)
        intersect_val = int(next(it))  # first of common tail
        for _ in range(X-1):
            next(it)  # discard rest
        out_lines.append(str(intersect_val))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

